/// <summary>
/// Distance sensor information for an onboard rangefinder.
/// </summary>
/// <param name="SystemId">The source MAVLink system ID.</param>
/// <param name="ComponentId">The source MAVLink component ID.</param>
/// <param name="EndPoint">The source transport endpoint.</param>
/// <param name="TimeBootMs">Timestamp (time since system boot).</param>
/// <param name="MinDistance">Minimum distance the sensor can measure</param>
/// <param name="MaxDistance">Maximum distance the sensor can measure</param>
/// <param name="CurrentDistance">Current distance reading</param>
/// <param name="Type">Type of distance sensor.</param>
/// <param name="Id">Onboard ID of the sensor</param>
/// <param name="Orientation">Direction the sensor faces. downward-facing: ROTATION_PITCH_270, upward-facing: ROTATION_PITCH_90, backward-facing: ROTATION_PITCH_180, forward-facing: ROTATION_NONE, left-facing: ROTATION_YAW_90, right-facing: ROTATION_YAW_270</param>
/// <param name="Covariance">Measurement variance. Max standard deviation is 6cm. UINT8_MAX if unknown.</param>
/// <param name="HorizontalFov">Horizontal Field of View (angle) where the distance measurement is valid and the field of view is known. Otherwise this is set to 0.</param>
/// <param name="VerticalFov">Vertical Field of View (angle) where the distance measurement is valid and the field of view is known. Otherwise this is set to 0.</param>
/// <param name="Quaternion">Quaternion of the sensor orientation in vehicle body frame (w, x, y, z order, zero-rotation is 1, 0, 0, 0). Zero-rotation is along the vehicle body x-axis. This field is required if the orientation is set to MAV_SENSOR_ROTATION_CUSTOM. Set it to 0 if invalid.&quot;</param>
