/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record DistanceSensorMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    uint TimeBootMs,
    ushort MinDistance,
    ushort MaxDistance,
    ushort CurrentDistance,
