/// <summary>
/// The location of a landing target. See: https://mavlink.io/en/services/landing_target.html
/// </summary>
/// <param name="SystemId">The source MAVLink system ID.</param>
/// <param name="ComponentId">The source MAVLink component ID.</param>
/// <param name="EndPoint">The source transport endpoint.</param>
/// <param name="TimeUsec">Timestamp (UNIX Epoch time or time since system boot). The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number.</param>
/// <param name="TargetNum">The ID of the target if multiple targets are present</param>
/// <param name="Frame">Coordinate frame used for following fields.</param>
/// <param name="AngleX">X-axis angular offset of the target from the center of the image</param>
/// <param name="AngleY">Y-axis angular offset of the target from the center of the image</param>
/// <param name="Distance">Distance to the target from the vehicle</param>
/// <param name="SizeX">Size of target along x-axis</param>
/// <param name="SizeY">Size of target along y-axis</param>
/// <param name="X">X Position of the landing target in MAV_FRAME</param>
/// <param name="Y">Y Position of the landing target in MAV_FRAME</param>
/// <param name="Z">Z Position of the landing target in MAV_FRAME</param>
/// <param name="Q">Quaternion of landing target orientation (w, x, y, z order, zero-rotation is 1, 0, 0, 0)</param>
/// <param name="Type">Type of landing target</param>
/// <param name="PositionValid">Position fields (x, y, z, q, type) contain valid target position information (MAV_BOOL_FALSE: invalid values). Values not equal to 0 or 1 are invalid.</param>
/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record LandingTargetMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    ulong TimeUsec,
    byte TargetNum,
    byte Frame,
    float AngleX,
    float AngleY,
    float Distance,
    float SizeX,
    float SizeY,
    float X,
    float Y,
    float Z,
    float[] Q,
    byte Type,
    byte PositionValid,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 149u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 30;
    internal override int MaximumPayloadLength => 60;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteUInt64(payload, 0, TimeUsec);
        MavLinkWireCodec.WriteSingle(payload, 8, AngleX);
        MavLinkWireCodec.WriteSingle(payload, 12, AngleY);
        MavLinkWireCodec.WriteSingle(payload, 16, Distance);
        MavLinkWireCodec.WriteSingle(payload, 20, SizeX);
        MavLinkWireCodec.WriteSingle(payload, 24, SizeY);
        MavLinkWireCodec.WriteByte(payload, 28, TargetNum);
        MavLinkWireCodec.WriteByte(payload, 29, Frame);
        MavLinkWireCodec.WriteSingle(payload, 30, X);
        MavLinkWireCodec.WriteSingle(payload, 34, Y);
        MavLinkWireCodec.WriteSingle(payload, 38, Z);
        MavLinkWireCodec.WriteArray(payload, 42, 4, 4, Q, MavLinkWireCodec.WriteSingle);
        MavLinkWireCodec.WriteByte(payload, 58, Type);
        MavLinkWireCodec.WriteByte(payload, 59, PositionValid);
    }
}

