        MavLinkWireCodec.WriteUInt32(payload, 4, LastAction);
        MavLinkWireCodec.WriteUInt32(payload, 8, LastRecovery);
        MavLinkWireCodec.WriteUInt32(payload, 12, LastClear);
        MavLinkWireCodec.WriteUInt16(payload, 16, BreachCount);
        MavLinkWireCodec.WriteByte(payload, 18, LimitsState);
        MavLinkWireCodec.WriteByte(payload, 19, ModsEnabled);
        MavLinkWireCodec.WriteByte(payload, 20, ModsRequired);
        MavLinkWireCodec.WriteByte(payload, 21, ModsTriggered);
