        MavLinkWireCodec.WriteInt32(payload, 4, Lng);
        MavLinkWireCodec.WriteInt16(payload, 8, Alt);
        MavLinkWireCodec.WriteInt16(payload, 10, BreakAlt);
        MavLinkWireCodec.WriteUInt16(payload, 12, LandDir);
        MavLinkWireCodec.WriteByte(payload, 14, TargetSystem);
        MavLinkWireCodec.WriteByte(payload, 15, TargetComponent);
        MavLinkWireCodec.WriteByte(payload, 16, Idx);
