    float OfsX,
    float OfsY,
    float OfsZ,
    float DiagX,
    float DiagY,
    float DiagZ,
    float OffdiagX,
    float OffdiagY,
    float OffdiagZ,
    float OrientationConfidence,
    byte OldOrientation,
    byte NewOrientation,
    float ScaleFactor,
    DateTimeOffset ReceivedAt)
