        MavLinkWireCodec.WriteSingle(payload, 4, OfsX);
        MavLinkWireCodec.WriteSingle(payload, 8, OfsY);
        MavLinkWireCodec.WriteSingle(payload, 12, OfsZ);
        MavLinkWireCodec.WriteSingle(payload, 16, DiagX);
        MavLinkWireCodec.WriteSingle(payload, 20, DiagY);
        MavLinkWireCodec.WriteSingle(payload, 24, DiagZ);
        MavLinkWireCodec.WriteSingle(payload, 28, OffdiagX);
        MavLinkWireCodec.WriteSingle(payload, 32, OffdiagY);
        MavLinkWireCodec.WriteSingle(payload, 36, OffdiagZ);
        MavLinkWireCodec.WriteByte(payload, 40, CompassId);
        MavLinkWireCodec.WriteByte(payload, 41, CalMask);
        MavLinkWireCodec.WriteByte(payload, 42, CalStatus);
        MavLinkWireCodec.WriteByte(payload, 43, Autosaved);
        MavLinkWireCodec.WriteSingle(payload, 44, OrientationConfidence);
        MavLinkWireCodec.WriteByte(payload, 48, OldOrientation);
        MavLinkWireCodec.WriteByte(payload, 49, NewOrientation);
        MavLinkWireCodec.WriteSingle(payload, 50, ScaleFactor);
    }
