/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record SetHomePositionMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    byte TargetSystem,
    int Latitude,
    int Longitude,
    int Altitude,
    float X,
    float Y,
    float Z,
    float[] Q,
    float ApproachX,
    float ApproachY,
    float ApproachZ,
    ulong TimeUsec,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 243u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 53;
    internal override int MaximumPayloadLength => 61;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteInt32(payload, 0, Latitude);
        MavLinkWireCodec.WriteInt32(payload, 4, Longitude);
        MavLinkWireCodec.WriteInt32(payload, 8, Altitude);
        MavLinkWireCodec.WriteSingle(payload, 12, X);
        MavLinkWireCodec.WriteSingle(payload, 16, Y);
        MavLinkWireCodec.WriteSingle(payload, 20, Z);
        MavLinkWireCodec.WriteArray(payload, 24, 4, 4, Q, MavLinkWireCodec.WriteSingle);
        MavLinkWireCodec.WriteSingle(payload, 40, ApproachX);
        MavLinkWireCodec.WriteSingle(payload, 44, ApproachY);
        MavLinkWireCodec.WriteSingle(payload, 48, ApproachZ);
