    {
        MavLinkWireCodec.WriteUInt16(payload, 0, MessageType);
        MavLinkWireCodec.WriteByte(payload, 2, TargetNetwork);
        MavLinkWireCodec.WriteByte(payload, 3, TargetSystem);
        MavLinkWireCodec.WriteByte(payload, 4, TargetComponent);
        MavLinkWireCodec.WriteArray(payload, 5, 249, 1, Payload, MavLinkWireCodec.WriteByte);
    }
