/// <param name="SensorType">Class id of the distance sensor type.</param>
/// <param name="Distances">Distance of obstacles around the vehicle with index 0 corresponding to north + angle_offset, unless otherwise specified in the frame. A value of 0 is valid and means that the obstacle is practically touching the sensor. A value of max_distance +1 means no obstacle is present. A value of UINT16_MAX for unknown/not used. In a array element, one unit corresponds to 1cm.</param>
/// <param name="Increment">Angular width in degrees of each array element. Increment direction is clockwise. This field is ignored if increment_f is non-zero.</param>
/// <param name="MinDistance">Minimum distance the sensor can measure.</param>
/// <param name="MaxDistance">Maximum distance the sensor can measure.</param>
/// <param name="IncrementF">Angular width in degrees of each array element as a float. If non-zero then this value is used instead of the uint8_t increment field. Positive is clockwise direction, negative is counter-clockwise.</param>
/// <param name="AngleOffset">Relative angle offset of the 0-index element in the distances array. Value of 0 corresponds to forward. Positive is clockwise direction, negative is counter-clockwise.</param>
/// <param name="Frame">Coordinate frame of reference for the yaw rotation and offset of the sensor data. Defaults to MAV_FRAME_GLOBAL, which is north aligned. For body-mounted sensors use MAV_FRAME_BODY_FRD, which is vehicle front aligned.</param>
/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record ObstacleDistanceMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    ulong TimeUsec,
    byte SensorType,
    ushort[] Distances,
    byte Increment,
    ushort MinDistance,
    ushort MaxDistance,
    float IncrementF,
    float AngleOffset,
    byte Frame,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 330u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 158;
    internal override int MaximumPayloadLength => 167;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteUInt64(payload, 0, TimeUsec);
        MavLinkWireCodec.WriteArray(payload, 8, 72, 2, Distances, MavLinkWireCodec.WriteUInt16);
        MavLinkWireCodec.WriteUInt16(payload, 152, MinDistance);
        MavLinkWireCodec.WriteUInt16(payload, 154, MaxDistance);
        MavLinkWireCodec.WriteByte(payload, 156, SensorType);
        MavLinkWireCodec.WriteByte(payload, 157, Increment);
        MavLinkWireCodec.WriteSingle(payload, 158, IncrementF);
        MavLinkWireCodec.WriteSingle(payload, 162, AngleOffset);
        MavLinkWireCodec.WriteByte(payload, 166, Frame);
    }
}

/// <summary>
/// Odometry message to communicate odometry information with an external interface. Fits ROS REP 147 standard for aerial vehicles (http://www.ros.org/reps/rep-0147.html).
/// </summary>
/// <param name="SystemId">The source MAVLink system ID.</param>
/// <param name="ComponentId">The source MAVLink component ID.</param>
/// <param name="EndPoint">The source transport endpoint.</param>
/// <param name="TimeUsec">Timestamp (UNIX Epoch time or time since system boot). The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number.</param>
/// <param name="FrameId">Coordinate frame of reference for the pose data.</param>
/// <param name="ChildFrameId">Coordinate frame of reference for the velocity in free space (twist) data.</param>
/// <param name="X">X Position</param>
/// <param name="Y">Y Position</param>
/// <param name="Z">Z Position</param>
/// <param name="Q">Quaternion components, w, x, y, z (1 0 0 0 is the null-rotation)</param>
/// <param name="Vx">X linear speed</param>
/// <param name="Vy">Y linear speed</param>
/// <param name="Vz">Z linear speed</param>
/// <param name="Rollspeed">Roll angular speed</param>
/// <param name="Pitchspeed">Pitch angular speed</param>
/// <param name="Yawspeed">Yaw angular speed</param>
/// <param name="PoseCovariance">Row-major representation of a 6x6 pose cross-covariance matrix upper right triangle (states: x, y, z, roll, pitch, yaw; first six entries are the first ROW, next five entries are the second ROW, etc.). If unknown, assign NaN value to first element in the array.</param>
/// <param name="VelocityCovariance">Row-major representation of a 6x6 velocity cross-covariance matrix upper right triangle (states: vx, vy, vz, rollspeed, pitchspeed, yawspeed; first six entries are the first ROW, next five entries are the second ROW, etc.). If unknown, assign NaN value to first element in the array.</param>
/// <param name="ResetCounter">Estimate reset counter. This should be incremented when the estimate resets in any of the dimensions (position, velocity, attitude, angular speed). This is designed to be used when e.g an external SLAM system detects a loop-closure and the estimate jumps.</param>
/// <param name="EstimatorType">Type of estimator that is providing the odometry.</param>
/// <param name="Quality">Optional odometry quality metric as a percentage. -1 = odometry has failed, 0 = unknown/unset quality, 1 = worst quality, 100 = best quality</param>
/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record OdometryMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    ulong TimeUsec,
    byte FrameId,
    byte ChildFrameId,
    float X,
    float Y,
    float Z,
    float[] Q,
    float Vx,
    float Vy,
    float Vz,
    float Rollspeed,
    float Pitchspeed,
    float Yawspeed,
    float[] PoseCovariance,
    float[] VelocityCovariance,
    byte ResetCounter,
    byte EstimatorType,
    sbyte Quality,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 331u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 230;
    internal override int MaximumPayloadLength => 233;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteUInt64(payload, 0, TimeUsec);
        MavLinkWireCodec.WriteSingle(payload, 8, X);
        MavLinkWireCodec.WriteSingle(payload, 12, Y);
        MavLinkWireCodec.WriteSingle(payload, 16, Z);
        MavLinkWireCodec.WriteArray(payload, 20, 4, 4, Q, MavLinkWireCodec.WriteSingle);
        MavLinkWireCodec.WriteSingle(payload, 36, Vx);
        MavLinkWireCodec.WriteSingle(payload, 40, Vy);
        MavLinkWireCodec.WriteSingle(payload, 44, Vz);
        MavLinkWireCodec.WriteSingle(payload, 48, Rollspeed);
        MavLinkWireCodec.WriteSingle(payload, 52, Pitchspeed);
        MavLinkWireCodec.WriteSingle(payload, 56, Yawspeed);
        MavLinkWireCodec.WriteArray(payload, 60, 21, 4, PoseCovariance, MavLinkWireCodec.WriteSingle);
        MavLinkWireCodec.WriteArray(payload, 144, 21, 4, VelocityCovariance, MavLinkWireCodec.WriteSingle);
        MavLinkWireCodec.WriteByte(payload, 228, FrameId);
        MavLinkWireCodec.WriteByte(payload, 229, ChildFrameId);
        MavLinkWireCodec.WriteByte(payload, 230, ResetCounter);
        MavLinkWireCodec.WriteByte(payload, 231, EstimatorType);
        MavLinkWireCodec.WriteSByte(payload, 232, Quality);
    }
}

/// <summary>
