/// <summary>
/// Send a secure command. Data should be signed with a private key corresponding with a public key known to the recipient. Signature should be over the concatenation of the sequence number (little-endian format), the operation (little-endian format) the data and the session key. For SECURE_COMMAND_GET_SESSION_KEY the session key should be zero length. The data array consists of the data followed by the signature. The sum of the data_length and the sig_length cannot be more than 220. The format of the data is command specific.
/// </summary>
/// <param name="SystemId">The source MAVLink system ID.</param>
/// <param name="ComponentId">The source MAVLink component ID.</param>
/// <param name="EndPoint">The source transport endpoint.</param>
/// <param name="TargetSystem">System ID.</param>
/// <param name="TargetComponent">Component ID.</param>
/// <param name="Sequence">Sequence ID for tagging reply.</param>
/// <param name="Operation">Operation being requested.</param>
/// <param name="DataLength">Data length.</param>
/// <param name="SigLength">Signature length.</param>
/// <param name="Data">Signed data.</param>
/// <param name="ReceivedAt">The reception timestamp.</param>
public sealed record SecureCommandMessage(
    byte SystemId,
    byte ComponentId,
    TransportEndPoint EndPoint,
    byte TargetSystem,
    byte TargetComponent,
    uint Sequence,
    uint Operation,
    byte DataLength,
    byte SigLength,
    byte[] Data,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 11004u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 232;
    internal override int MaximumPayloadLength => 232;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteUInt32(payload, 0, Sequence);
        MavLinkWireCodec.WriteUInt32(payload, 4, Operation);
        MavLinkWireCodec.WriteByte(payload, 8, TargetSystem);
        MavLinkWireCodec.WriteByte(payload, 9, TargetComponent);
        MavLinkWireCodec.WriteByte(payload, 10, DataLength);
        MavLinkWireCodec.WriteByte(payload, 11, SigLength);
        MavLinkWireCodec.WriteArray(payload, 12, 220, 1, Data, MavLinkWireCodec.WriteByte);
    }
}

