/// <param name="HorizontalAccuracy">The accuracy of the horizontal position.</param>
/// <param name="VerticalAccuracy">The accuracy of the vertical position.</param>
/// <param name="BarometerAccuracy">The accuracy of the barometric altitude.</param>
/// <param name="SpeedAccuracy">The accuracy of the horizontal and vertical speed.</param>
/// <param name="Timestamp">Seconds after the full hour with reference to UTC time. Typically the GPS outputs a time-of-week value in milliseconds. First convert that to UTC and then convert for this field using ((float) (time_week_ms % (60*60*1000))) / 1000. If unknown: 0xFFFF.</param>
