    byte DataPage,
    byte LastPageIndex,
    byte Length,
    uint Timestamp,
    byte[] AuthenticationData,
    DateTimeOffset ReceivedAt)
    : GeneratedMavLinkMessage(SystemId, ComponentId, 12902u, EndPoint, ReceivedAt)
{
    internal override int MinimumPayloadLength => 53;
    internal override int MaximumPayloadLength => 53;

    internal override void WritePayload(Span<byte> payload)
    {
        MavLinkWireCodec.WriteUInt32(payload, 0, Timestamp);
        MavLinkWireCodec.WriteByte(payload, 4, TargetSystem);
        MavLinkWireCodec.WriteByte(payload, 5, TargetComponent);
        MavLinkWireCodec.WriteArray(payload, 6, 20, 1, IdOrMac, MavLinkWireCodec.WriteByte);
        MavLinkWireCodec.WriteByte(payload, 26, AuthenticationType);
