        MavLinkWireCodec.WriteSingle(payload, 8, OperatorAltitudeGeo);
        MavLinkWireCodec.WriteUInt32(payload, 12, Timestamp);
        MavLinkWireCodec.WriteByte(payload, 16, TargetSystem);
        MavLinkWireCodec.WriteByte(payload, 17, TargetComponent);
    }
}

