        MavLinkWireCodec.WriteSingle(payload, 4, Max1);
        MavLinkWireCodec.WriteSingle(payload, 8, Min2);
        MavLinkWireCodec.WriteSingle(payload, 12, Max2);
        MavLinkWireCodec.WriteSingle(payload, 16, Min3);
        MavLinkWireCodec.WriteSingle(payload, 20, Max3);
        MavLinkWireCodec.WriteSingle(payload, 24, Min4);
        MavLinkWireCodec.WriteSingle(payload, 28, Max4);
        MavLinkWireCodec.WriteSingle(payload, 32, Min5);
